import { TrailColorComponent } from "./TrailColorComponent.js";
export class TrailColorCoords {
    h;
    l;
    s;
    constructor() {
        this.h = new TrailColorComponent();
        this.s = new TrailColorComponent();
        this.l = new TrailColorComponent();
    }
    load(data) {
        if (!data) {
            return;
        }
        if (data.h) {
            this.h ??= new TrailColorComponent();
            this.h.load(data.h);
        }
        if (data.s) {
            this.s ??= new TrailColorComponent();
            this.s.load(data.s);
        }
        if (data.l) {
            this.l ??= new TrailColorComponent();
            this.l.load(data.l);
        }
    }
}
